const raw = $input.first().json;
const body = (raw.body && raw.body.sessionId) ? raw.body : raw;
const headers = raw.headers || {};
const origin = String(headers.origin || headers.Origin || '').trim();
const ip = String(headers['x-forwarded-for'] || headers['x-real-ip'] || '').split(',')[0].trim() || 'unknown';
const { sessionId, event, messages, lastMessage, platform, timestamp } = body;

// ---- GUARDS ----
const allowedOrigins = ($env.SITE_CHAT_ORIGINS || 'https://mycheagent.ru,https://studio-che.ru').split(',').map(s=>s.trim()).filter(Boolean);
if (!origin || !allowedOrigins.includes(origin)) {
  return [{ json: { _blocked: true, statusCode: 403, reason: 'origin_not_allowed', origin } }];
}
if (!sessionId || typeof sessionId !== 'string' || sessionId.length < 6 || sessionId.length > 128) {
  return [{ json: { _blocked: true, statusCode: 400, reason: 'bad_session_id' } }];
}
// Payload size cap (messages.length & text length)
const msgs = Array.isArray(messages) ? messages : [];
if (msgs.length > 50) {
  return [{ json: { _blocked: true, statusCode: 413, reason: 'too_many_messages' } }];
}
const totalChars = msgs.reduce((s,m)=>s+String(m?.content||'').length,0) + String(lastMessage||'').length;
if (totalChars > 20000) {
  return [{ json: { _blocked: true, statusCode: 413, reason: 'payload_too_large' } }];
}

// Rate-limit: sessionId OR ip, sliding 60s window, 20 requests
const store = $getWorkflowStaticData('global');
if (!store.rate) store.rate = {};
const now = Date.now();
const WINDOW = 60 * 1000;
const LIMIT = 20;
const keys = ['s:'+sessionId, 'i:'+ip];
for (const k of keys) {
  const bucket = store.rate[k] || { count: 0, resetAt: now + WINDOW };
  if (now > bucket.resetAt) { bucket.count = 0; bucket.resetAt = now + WINDOW; }
  bucket.count += 1;
  store.rate[k] = bucket;
  if (bucket.count > LIMIT) {
    return [{ json: { _blocked: true, statusCode: 429, reason: 'rate_limited', key: k, count: bucket.count } }];
  }
}
// GC old buckets
if (Object.keys(store.rate).length > 2000) {
  for (const k of Object.keys(store.rate)) {
    if (store.rate[k].resetAt < now) delete store.rate[k];
  }
}

// ---- PROMPT ----
if (!store.siteConfig) store.siteConfig = {};
const DEFAULT_BASE = `Ты — ИИ-ассистент обучающей платформы "Студия ЧЕ". Тебя зовут "Зевс, ассистент Видякова Дениса".

ТВОЯ РОЛЬ: Ты эксперт-консультант по видеопроизводству и ИИ-инструментам. Помогаешь пользователям выбрать курс, отвечаешь на вопросы по теме, мотивируешь учиться.

НАПРАВЛЕНИЯ ПЛАТФОРМЫ:
1. ВИДЕОМОНТАЖ — Adobe Premiere Pro, After Effects. Таймлайн, цветокоррекция, звук, переходы, эффекты, экспорт, кодеки (H.264, H.265, ProRes), разрешения, фреймрейт, многокамерный монтаж.
2. ИИ ГЕНЕРАЦИИ — DALL-E, Kling, Nano Banano, VEO 3. Генерация видео из текста и изображений, промпт-инжиниринг, стили, параметры, upscale, img2vid, text2vid. Генерация музыки: Suno.
3. ИИ ДЛЯ БИЗНЕСА — ChatGPT, Claude, автоматизация контента, сценарии, субтитры через Whisper, AI-озвучка (ElevenLabs, HeyGen), чат-боты, воронки продаж, автоматизация видеопродакшена, автопостинг, контент-планы.

УСЛОВИЯ: Разовая оплата, доступ навсегда. Никаких подписок. Оплата через ЮKassa. Последовательное прохождение уроков. Есть домашние задания. Общий чат в каждом курсе.

ПРАВИЛА ОТВЕТОВ:
- Отвечай на русском языке
- Будь дружелюбным, лаконичным, по делу
- Используй эмодзи умеренно (1-2 на сообщение)
- Рекомендуй конкретные курсы, когда уместно
- Если вопрос не по теме — вежливо верни к теме видеопроизводства и ИИ
- Максимум 3-4 предложения на ответ
- Не выдумывай курсы, которых нет в списке
- Если спрашивают про цены — называй точные
- Мотивируй людей начать обучение`;
const DEFAULT_COURSES = [
  { name: 'Основы видеомонтажа и анимации в Premiere Pro и After Effects', price: '4 990 ₽', level: 'для новичков' }
];
if (!store.siteConfig.basePrompt) store.siteConfig.basePrompt = DEFAULT_BASE;
if (!store.siteConfig.courses) store.siteConfig.courses = DEFAULT_COURSES;
const coursesList = store.siteConfig.courses.map((c,i) => `${i+1}. "${c.name}" — ${c.price}${c.level ? ' ('+c.level+')' : ''}`).join('\n');
const systemPrompt = store.siteConfig.basePrompt + '\n\nКУРСЫ НА ПЛАТФОРМЕ:\n' + coursesList;

return [{ json: { _blocked: false, origin, sessionId, event: event || 'message', messages: msgs, lastMessage: lastMessage || '', platform: platform || 'Студия ЧЕ', timestamp, systemPrompt } }];

const res = $input.first().json;
const parsed = $('Parse Event').first().json;
if (!res.choices || res.error) {
  const reply = 'Сейчас не могу ответить — попробуй через минуту 🙏';
  return [{ json: { reply, origin: parsed.origin, _error: res.error?.message || 'gpt_failed' } }];
}
const reply = res.choices[0].message.content.trim();
return [{ json: { reply, origin: parsed.origin } }];

const res = $input.first().json;
const summary = res.choices?.[0]?.message?.content?.trim() || 'Не удалось сгенерировать резюме';
const parsed = $('Parse Event').item.json;
const ts = parsed.timestamp ? new Date(parsed.timestamp).toLocaleString('ru', { day:'numeric', month:'long', hour:'2-digit', minute:'2-digit' }) : new Date().toLocaleString('ru');
const msgCount = parsed.messages.length;
const tgText = `📊 *Диалог завершён* | ${ts}\n🏢 ${parsed.platform} | ${msgCount} сообщений\n\n${summary}`;
const pwaText = `📊 Диалог на сайте (${parsed.platform}, ${ts}, ${msgCount} сообщ.):\n${summary}`;
return [{ json: { tgText, pwaText, origin: parsed.origin } }];
